#include <iostream>
using namespace std;

int main() {
    int number, reversedNumber = 0, sumOfDigits = 0, digit;

    cin >> number;

    int isNegative = 0;

    // Check if the number is negative
    if (number < 0) {
        isNegative = 1;
        number = -number;  // Make the number positive for reversal and summing
    }

    // Save the original number for later use
    int originalNumber = number;

    while (number != 0) {
        digit = number % 10;        // Extract the last digit
        sumOfDigits += digit;       // Add it to the sum of digits
        reversedNumber = reversedNumber * 10 + digit;  // Build the reversed number
        number /= 10;               // Remove the last digit
    }

    // If the original number was negative, make the reversed number negative
    if (isNegative) {
        reversedNumber = -reversedNumber;
    }

    // Display the reversed number and the sum of digits
    cout << "Reversed: " << reversedNumber << endl;
    cout << "Sum: " << sumOfDigits << endl;

    return 0;
}

